// 空数据保护:如果没有新文章,直接结束
const rawItem = $input.item.json;
if (!rawItem || !rawItem.title) {
  return { json: { _skip: true } };
}

// 处理所有文章(n8n 会自动把每个 item 单独跑一次)
const wpPost = $input.item.json;

// HTML 转纯文本的小函数:去掉所有 HTML 标签,解码常见实体
function stripHtml(html) {
  if (!html) return '';
  return html
    .replace(/<br\s*\/?>/gi, '\n')           // <br> 转换行
    .replace(/<\/p>/gi, '\n\n')              // </p> 转双换行
    .replace(/<[^>]+>/g, '')                 // 删所有其他标签
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#8217;/g, "'")
    .replace(/&#8220;/g, '"')
    .replace(/&#8221;/g, '"')
    .replace(/\n{3,}/g, '\n\n')              // 压缩多余换行
    .trim();
}

// 提取核心字段
const title = stripHtml(wpPost.title?.rendered || '');
const summary = stripHtml(wpPost.excerpt?.rendered || '');
const fullContent = stripHtml(wpPost.content?.rendered || '');
const url = wpPost.link || '';

// 日期格式化:WordPress 返回 "2026-04-09T14:30:00",数据库要 "2026-04-09"
const pubDate = (wpPost.date || '').substring(0, 10);

// 生成 slug:优先用 WP 的 slug,做 URL 解码 + 安全处理
let cleanSlug;
try {
  // WordPress 默认会把中文 slug 做 URL 编码,这里解码回中文
  cleanSlug = wpPost.slug ? decodeURIComponent(wpPost.slug) : '';
} catch (e) {
  // decodeURIComponent 失败的话直接用原始 slug
  cleanSlug = wpPost.slug || '';
}

// 如果解码后仍是空或全是垃圾字符,用 wp_id 兜底
if (!cleanSlug || cleanSlug.length < 2) {
  cleanSlug = `wp-${wpPost.id}`;
}

// 限制长度:中文每字 3 字节,数据库虽然能存超长,但 slug 太长不利于 URL 和管理
// 取前 50 个字符
if (cleanSlug.length > 50) {
  cleanSlug = cleanSlug.substring(0, 50);
}

// 最终拼装:日期 + slug,例如 "2026-04-14-女性专属抗衰旅程-goddess-retreats"
const slug = `${pubDate}-${cleanSlug}`;

// source 字段:因为这是从你自己的 WordPress 来的,默认标记为 WordPress 原创
// 未来从 RSS 抓的内容,这里会是 "Longevity.Technology" 等
const source = 'Longevity Foresight 原创';

// has_chunks 先标 false,后续如果跑切片流程再 UPDATE
const hasChunks = false;

// 判断是否需要切片(阶段 2 才实际做,现在只是标记)
const needsChunking = fullContent.length > 1000;

return {
  json: {
    wp_id: wpPost.id,           // 保留 WordPress 原 ID,万一后续要回查
    slug: slug,
    title: title,
    summary: summary,
    full_content: fullContent || null,   // 没有全文就传 null
    url: url,
    pub_date: pubDate,
    source: source,
    has_chunks: hasChunks,
    needs_chunking: needsChunking,       // 内部标记,不入库
    content_length: fullContent.length   // 供调试
  }
};

// 拿到节点 4(DeepSeek)的返回
const aiResponse = $input.item.json
const rawContent = aiResponse.choices?.[0]?.message?.content || '';

// 清洗可能的 markdown 代码块包裹
let cleanedContent = rawContent.trim();
if (cleanedContent.startsWith('```')) {
  cleanedContent = cleanedContent
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/, '')
    .trim();
}

// 解析 JSON,加异常保护
let tags;
try {
  tags = JSON.parse(cleanedContent);
} catch (e) {
  console.log('AI 返回解析失败,原文:', rawContent);
  tags = {
    category: null,
    substance: [],
    mechanism: [],
    organ: [],
    evidence: null,
    source_tag: null,
    person: [],
    person_other: [],
    org: [],
    org_other: [],
    _parse_error: rawContent.substring(0, 300)
  };
}

// 从节点 3(Clean_WP_Data)拿清洗后的文章数据
const article = $('Clean_WP_Data').item.json;

// 提取 category 为独立字段(写入 articles.category 列)
// metadata 里只保留其他轴
const category = tags.category || null;
const metadata = {
  substance: tags.substance || [],
  mechanism: tags.mechanism || [],
  organ: tags.organ || [],
  evidence: tags.evidence || null,
  source_tag: tags.source_tag || null,
  person: tags.person || [],
  person_other: tags.person_other || [],
  org: tags.org || [],
  org_other: tags.org_other || []
};

// 如果解析失败,把错误记录下来
if (tags._parse_error) {
  metadata._parse_error = tags._parse_error;
}

// 准备给 embedding API 的输入文本(用标题+摘要,不用全文)
const textToEmbed = `${article.title}。${article.summary}`;

return {
  json: {
    // 原始文章字段
    slug: article.slug,
    title: article.title,
    summary: article.summary,
    full_content: article.full_content,
    url: article.url,
    pub_date: article.pub_date,
    source: article.source,
    has_chunks: article.has_chunks,

    // AI 打标结果
    category: category,
    metadata: metadata,

    // 给下一节点(embedding)用
    text_to_embed: textToEmbed
  }
};

// 从节点 6 拿 embedding 向量
const embeddingResponse = $input.item.json;
const embedding = embeddingResponse.data?.[0]?.embedding;

// 安全校验:维度必须是 1024
if (!embedding || embedding.length !== 1024) {
  throw new Error(`Embedding 异常: 预期 1024 维, 实际 ${embedding ? embedding.length : 0} 维`);
}

// 从节点 5(Parse_Tags)拿完整数据
const article = $('Parse_Tags').item.json;

// PGVector 接受的向量格式是字符串: '[0.1,0.2,0.3]'
const embeddingStr = '[' + embedding.join(',') + ']';

return {
  json: {
    slug: article.slug,
    title: article.title,
    summary: article.summary,
    full_content: article.full_content,
    url: article.url,
    pub_date: article.pub_date,
    source: article.source,
    category: article.category,
    metadata: article.metadata,
    summary_embedding: embeddingStr,
    has_chunks: article.has_chunks
  }
};

const insertedArticle = $input.all()[0].json;
const articleId = insertedArticle.id;

const articleData = $('Clean_WP_Data').item.json;
const fullContent = articleData.full_content || '';
const title = articleData.title || '';

if (!articleId) {
  throw new Error('未拿到 article_id');
}

if (!fullContent || fullContent.length < 100) {
  throw new Error('full_content 异常短,不应进入切片流程');
}

const CHUNK_SIZE = 400;
const OVERLAP = 60;
const MIN_CHUNK_LENGTH = 30;

function findBestCutPoint(text, targetPos, searchRange) {
  // 在 targetPos 前后 searchRange 范围内找最佳切点
  const start = Math.max(0, targetPos - searchRange);
  const end = Math.min(text.length, targetPos + searchRange);
  const segment = text.substring(start, end);

  // 按优先级定义切点模式
  const patterns = [
    /\n\n/g,              // 段落分隔(最优)
    /\n/g,                // 换行
    /[。！？；!?;]/g,      // 句末标点
    /[，、,]/g,            // 句中标点
    /\s/g                 // 空格(英文词边界)
  ];

  for (const pattern of patterns) {
    pattern.lastIndex = 0;
    let bestPos = -1;
    let bestDist = Infinity;
    let match;

    while ((match = pattern.exec(segment)) !== null) {
      const absPos = start + match.index;
      const dist = Math.abs(absPos - targetPos);
      // 优先选 targetPos 之前的(当前片段稍短),但之后的也接受
      if (dist < bestDist) {
        bestDist = dist;
        bestPos = absPos;
      }
    }

    if (bestPos !== -1) {
      return bestPos + 1;  // +1 把标点包含在当前片段
    }
  }

  return -1;  // 没找到任何切点
}

function splitIntoChunks(text) {
  const chunks = [];
  let start = 0;
  let safetyCounter = 0;
  const maxIterations = Math.ceil(text.length / (CHUNK_SIZE - OVERLAP)) + 10;

  while (start < text.length) {
    // 防死循环
    safetyCounter++;
    if (safetyCounter > maxIterations) {
      // 把剩余文本作为最后一片
      const remaining = text.substring(start).trim();
      if (remaining.length > MIN_CHUNK_LENGTH) {
        chunks.push(remaining);
      }
      break;
    }

    let end = Math.min(start + CHUNK_SIZE, text.length);

    // 如果还没到文本末尾,寻找最佳切点
    if (end < text.length) {
      const cutPoint = findBestCutPoint(text, end, 80);
      if (cutPoint !== -1 && cutPoint > start + 50) {
        // 切点必须比起点至少远 50 字,否则会产生过短片段
        end = cutPoint;
      }
      // 如果没找到切点,就在 end 处硬切(极罕见)
    }

    const chunk = text.substring(start, end).trim();
    if (chunk.length > MIN_CHUNK_LENGTH) {
      chunks.push(chunk);
    }

    // 计算下一片的起点
    const nextStart = end - OVERLAP;

    // 确保 start 一定往前推进,防止死循环
    if (nextStart <= start) {
      start = end;  // 强制从 end 开始,不重叠
    } else {
      start = nextStart;
    }

    // 已经处理到文本末尾
    if (end >= text.length) break;
  }

  return chunks;
}

const chunks = splitIntoChunks(fullContent);

return chunks.map((content, index) => ({
  json: {
    article_id: articleId,
    chunk_index: index,
    content: content,
    token_count: Math.ceil(content.length / 1.5),
    text_to_embed: `${title}。${content}`
  }
}));

// 当前 node 的 input 包含 5 个 items(每个是 embedding API 的返回)
// 我们要从 Split_Chunks 拿到每片的 article_id/chunk_index/content/token_count
// 然后把 embedding 向量拼上

const allItems = $input.all();
const results = [];

for (let i = 0; i < allItems.length; i++) {
  const embedResponse = allItems[i].json;
  const embedding = embedResponse.data?.[0]?.embedding;

  if (!embedding || embedding.length !== 1024) {
    throw new Error(`第 ${i} 片 embedding 异常,维度 ${embedding ? embedding.length : 0}`);
  }

  // 从 Split_Chunks 取对应索引的原始数据
  const chunkData = $('Split_Chunks').all()[i].json;

  // PGVector 向量字符串格式
  const embeddingStr = '[' + embedding.join(',') + ']';

  results.push({
    json: {
      article_id: chunkData.article_id,
      chunk_index: chunkData.chunk_index,
      content: chunkData.content,
      token_count: chunkData.token_count,
      embedding: embeddingStr
    }
  });
}

return results;
